+  const workspaceLockfile = `${WORKSPACE_ROOT}/package-lock.json`;
+  const lockfileCheck = await sandbox.exec(
+    `if [ -f ${shellQuote(workspacePackageJson)} ] && [ -f ${shellQuote(workspaceLockfile)} ]; then echo workspace; else echo project; fi`
